using System;
using System.Reflection;
using System.Linq;

var dllPaths = new[]
{
    "/home/runner/.nuget/packages/modelcontextprotocol/1.2.0/lib/net8.0/ModelContextProtocol.dll",
    "/home/runner/.nuget/packages/modelcontextprotocol.core/1.2.0/lib/net8.0/ModelContextProtocol.Core.dll",
    "/home/runner/.nuget/packages/modelcontextprotocol.aspnetcore/1.2.0/lib/net8.0/ModelContextProtocol.AspNetCore.dll"
};

foreach (var path in dllPaths)
{
    Console.WriteLine($"\n{'='*80}");
    Console.WriteLine($"Assembly: {path}");
    Console.WriteLine($"{'='*80}");

    if (!File.Exists(path))
    {
        Console.WriteLine($"File not found: {path}");
        continue;
    }

    try
    {
        var asm = Assembly.LoadFrom(path);
        var types = asm.GetTypes().OrderBy(t => t.Namespace + "." + t.Name).ToArray();

        Console.WriteLine($"Total Types: {types.Length}\n");

        foreach (var type in types)
        {
            // Print namespace and type info
            Console.WriteLine($"\nNamespace: {type.Namespace}");
            Console.WriteLine($"Type: {type.Name}");
            Console.WriteLine($"  Base: {type.BaseType?.Name}");

            // Print attributes
            var attrs = type.GetCustomAttributes(false);
            if (attrs.Length > 0)
            {
                Console.WriteLine($"  Attributes:");
                foreach (var attr in attrs)
                {
                    Console.WriteLine($"    [{attr.GetType().Name}]");
                }
            }

            // Print public methods and properties
            var methods = type.GetMethods(BindingFlags.Public | BindingFlags.DeclaredOnly);
            var properties = type.GetProperties(BindingFlags.Public | BindingFlags.DeclaredOnly);

            if (methods.Length > 0)
            {
                Console.WriteLine($"  Methods:");
                foreach (var m in methods)
                {
                    var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                    Console.WriteLine($"    {m.ReturnType.Name} {m.Name}({parms})");
                }
            }

            if (properties.Length > 0)
            {
                Console.WriteLine($"  Properties:");
                foreach (var p in properties)
                {
                    Console.WriteLine($"    {p.PropertyType.Name} {p.Name}");
                }
            }
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }
}
