using System;
using System.Reflection;
using System.Linq;

var dllPath = "/home/runner/.nuget/packages/modelcontextprotocol/1.2.0/lib/net8.0/ModelContextProtocol.dll";

var asm = Assembly.LoadFrom(dllPath);

// Get all types with "ServerBuilder", "Extension", or in DependencyInjection namespace
var types = asm.GetTypes()
    .Where(t => t.Name.Contains("ServerBuilder") || 
           t.Name.Contains("Extension") ||
           t.Namespace?.Contains("DependencyInjection") == true ||
           (t.Namespace == "ModelContextProtocol.Server"))
    .OrderBy(t => t.FullName)
    .ToArray();

foreach (var type in types)
{
    if (type.IsPublic)
    {
        Console.WriteLine($"\n=== {type.FullName} ===");

        // Static methods for extension methods
        var staticMethods = type.GetMethods(BindingFlags.Static | BindingFlags.Public | BindingFlags.DeclaredOnly);
        if (staticMethods.Length > 0)
        {
            foreach (var m in staticMethods.Take(10))
            {
                var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({parms})");
            }
        }
    }
}
